sed -i 's/val micPermissionLauncher = rememberLauncherForActivityResult(ActivityResultContracts.RequestPermission()) { isGranted ->/val speechLauncher = rememberLauncherForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->\n        if (result.resultCode == android.app.Activity.RESULT_OK) {\n            val data = result.data\n            val results = data?.getStringArrayListExtra(android.speech.RecognizerIntent.EXTRA_RESULTS)\n            if (!results.isNullOrEmpty()) {\n                question = results[0]\n            }\n        }\n    }/g' app/src/main/java/com/example/ui/screens/SolverScreen.kt

sed -i 's/if (isGranted) {/ /g' app/src/main/java/com/example/ui/screens/SolverScreen.kt
sed -i 's/coroutineScope.launch { snackbarHostState.showSnackbar("Mic permission granted") }/ /g' app/src/main/java/com/example/ui/screens/SolverScreen.kt
sed -i 's/} else {/ /g' app/src/main/java/com/example/ui/screens/SolverScreen.kt
sed -i 's/coroutineScope.launch { snackbarHostState.showSnackbar("Mic permission denied") }/ /g' app/src/main/java/com/example/ui/screens/SolverScreen.kt

sed -i 's/micPermissionLauncher.launch(android.Manifest.permission.RECORD_AUDIO)/val intent = android.content.Intent(android.speech.RecognizerIntent.ACTION_RECOGNIZE_SPEECH).apply {\n                                    putExtra(android.speech.RecognizerIntent.EXTRA_LANGUAGE_MODEL, android.speech.RecognizerIntent.LANGUAGE_MODEL_FREE_FORM)\n                                    putExtra(android.speech.RecognizerIntent.EXTRA_LANGUAGE, if (lang == "hi") "hi-IN" else "en-US")\n                                }\n                                try {\n                                    speechLauncher.launch(intent)\n                                } catch (e: Exception) {\n                                    coroutineScope.launch { snackbarHostState.showSnackbar("Speech recognition not available") }\n                                }/g' app/src/main/java/com/example/ui/screens/SolverScreen.kt
